const input = $input.first().json;
const countryCode = (input.country_code || 'DE').toUpperCase();
const year = input.year || new Date().getFullYear().toString();
const mode = input.mode || 'year';

const BASE = 'https://date.nager.at/api/v3';

try {
  let holidays;
  if (mode === 'next' || mode === 'upcoming') {
    holidays = await helpers.httpRequest({
      method: 'GET',
      url: BASE + '/NextPublicHolidays/' + countryCode
    });
  } else {
    holidays = await helpers.httpRequest({
      method: 'GET',
      url: BASE + '/PublicHolidays/' + year + '/' + countryCode
    });
  }

  if (!Array.isArray(holidays) || holidays.length === 0) {
    return [{ json: { result: 'No public holidays found for ' + countryCode + ' (' + year + ').' } }];
  }

  let result = 'Public Holidays for ' + countryCode;
  if (mode !== 'next' && mode !== 'upcoming') result += ' (' + year + ')';
  result += ':\n\n';

  for (const h of holidays) {
    const dateStr = h.date;
    const name = h.localName && h.localName !== h.name
      ? h.localName + ' (' + h.name + ')'
      : h.name;
    const types = h.types ? h.types.join(', ') : '';
    result += '- ' + dateStr + ': ' + name;
    if (types && types !== 'Public') result += ' [' + types + ']';
    result += '\n';
  }

  result += '\nTotal: ' + holidays.length + ' holidays';
  return [{ json: { result } }];
} catch (err) {
  if (err.message && err.message.includes('404')) {
    return [{ json: { error: 'Country code "' + countryCode + '" not found. Use ISO 3166-1 alpha-2 codes (e.g. DE, US, AT, CH, FR).' } }];
  }
  return [{ json: { error: 'Failed to fetch holidays: ' + err.message } }];
}
